        if (!y || !y.chargesFixes || !y.chargesFixes[op.key]) { log.status = 'skip'; log.reason = 'clé absente'; break; }
        delete y.chargesFixes[op.key]; log.key = op.key; log.removed = true; break;
      }
      case 'rename_charge_fixe': {
        if (!y || !y.chargesFixes || !y.chargesFixes[op.key]) { log.status = 'skip'; log.reason = 'clé absente'; break; }
        const lbl = pickStr(op, 'label', 'nom');
        if (lbl === null) { log.status = 'error'; log.reason = 'label manquant'; break; }
        const old = y.chargesFixes[op.key].label;
        writeCharge(y.chargesFixes[op.key], null, lbl);
        log.key = op.key; log.avant = old; log.apres = lbl; break;
      }
      case 'update_charge_fixe': {
        if (!y || !y.chargesFixes || !y.chargesFixes[op.key]) { log.status = 'skip'; log.reason = 'clé absente'; break; }
        const v = pickNum(op, 'valeur', 'montant', 'value', 'amount');
        const lbl = pickStr(op, 'label', 'nom');
        const target = y.chargesFixes[op.key];
        const changes = {};
        if (v !== null) { changes.valeur = { avant: target.valeur, apres: v }; }
        if (lbl !== null) { changes.label = { avant: target.label, apres: lbl }; }
        if (Object.keys(changes).length === 0) { log.status = 'error'; log.reason = 'aucun champ à mettre à jour'; break; }
        writeCharge(target, v, lbl);
        log.key = op.key; log.changes = changes; break;
      }
      case 'add_charge_fixe_exception': {
        if (!y || !y.chargesFixes || !y.chargesFixes[op.key]) { log.status = 'skip'; log.reason = 'clé absente'; break; }
        if (!Array.isArray(y.chargesFixes[op.key].exceptions)) y.chargesFixes[op.key].exceptions = [];
        const id = Date.now() + Math.floor(Math.random() * 1000);
        y.chargesFixes[op.key].exceptions.push({ id, moisDebut: Number(op.moisDebut), moisFin: Number(op.moisFin), nouvelleValeur: Number(op.nouvelleValeur) });
        y.chargesFixes[op.key].showExceptions = true;
        log.key = op.key; log.id = id; break;
      }
      case 'remove_charge_fixe_exception': {
        if (!y || !y.chargesFixes || !y.chargesFixes[op.key]) { log.status = 'skip'; log.reason = 'clé absente'; break; }
        const before = (y.chargesFixes[op.key].exceptions || []).length;
        y.chargesFixes[op.key].exceptions = (y.chargesFixes[op.key].exceptions || []).filter(e => Number(e.id) !== Number(op.id));
        log.key = op.key; log.supprimees = before - y.chargesFixes[op.key].exceptions.length; break;
      }

      // ═══ CHARGES VARIABLES ═══
      case 'set_charge_variable': {
        if (!y || !y.chargesVariables || !y.chargesVariables[op.key]) { log.status = 'skip'; log.reason = 'année ou clé absente'; break; }
        const v = pickNum(op, 'valeur', 'montant', 'value', 'amount');
        if (v === null) { log.status = 'error'; log.reason = 'aucune valeur numérique fournie'; break; }
        const item = y.chargesVariables[op.key];
        const old = item.valeur;
        // ── v13.9 : redistribution proportionnelle si details existent ──
        if (item.details && item.details.length > 0) {
          const currentSum = item.details.reduce((s, d) => s + (Number(d.montant) || 0), 0);
          if (currentSum === 0) {
            log.status = 'error';
            log.requires_redistribution = true;
            log.reason = 'Répartition proportionnelle impossible : toutes les sous-lignes sont à 0. Précise comment ventiler le nouveau total.';
            log.nouveau_total = v;
            log.lignes = item.details.map(d => ({ id: d.id, nom: d.nom, montant_actuel: d.montant }));
            break;
          }
          const ratio = v / currentSum;
          let distributed = 0;
          for (let i = 0; i < item.details.length - 1; i++) {
            const nm = Math.round(item.details[i].montant * ratio);
            item.details[i].montant = nm;
            distributed += nm;
          }
          item.details[item.details.length - 1].montant = v - distributed;
          log.redistribution = 'proportionnelle';
          log.ratio_applique = Math.round(ratio * 1000) / 1000;
          log.details_apres = item.details.map(d => ({ nom: d.nom, montant: d.montant }));
        }
        writeCharge(item, v, null);
        log.key = op.key; log.avant = old; log.apres = v; break;
      }
      case 'add_charge_variable': {
        if (!y) { log.status = 'skip'; log.reason = 'année absente'; break; }
        if (!y.chargesVariables) y.chargesVariables = {};
        if (y.chargesVariables[op.key]) { log.status = 'skip'; log.reason = 'clé existe déjà — utilise update_charge_variable'; break; }
        const v = pickNum(op, 'valeur', 'montant', 'value', 'amount') ?? 0;
        const periode = (op.periode === 'semaine' || op.periode === 'mois') ? op.periode : 'mois';
        const lbl = pickStr(op, 'label', 'nom') || op.key;
        y.chargesVariables[op.key] = { label: lbl, valeur: v, periode, showDetails: false, details: [] };
        log.key = op.key; log.created = true; log.valeur = v; log.periode = periode; break;
      }
      case 'remove_charge_variable': {
        if (!y || !y.chargesVariables || !y.chargesVariables[op.key]) { log.status = 'skip'; log.reason = 'clé absente'; break; }
        delete y.chargesVariables[op.key]; log.key = op.key; log.removed = true; break;
      }
      case 'set_charge_variable_periode': {
        if (!y || !y.chargesVariables || !y.chargesVariables[op.key]) { log.status = 'skip'; log.reason = 'clé absente'; break; }
        if (op.periode !== 'mois' && op.periode !== 'semaine') { log.status = 'error'; log.reason = 'periode doit être "mois" ou "semaine"'; break; }
        const old = y.chargesVariables[op.key].periode;
        y.chargesVariables[op.key].periode = op.periode;
        log.key = op.key; log.avant = old; log.apres = op.periode; break;
      }
      case 'update_charge_variable': {
        if (!y || !y.chargesVariables || !y.chargesVariables[op.key]) { log.status = 'skip'; log.reason = 'clé absente'; break; }
        const v = pickNum(op, 'valeur', 'montant', 'value', 'amount');
        const lbl = pickStr(op, 'label', 'nom');
        const per = (op.periode === 'mois' || op.periode === 'semaine') ? op.periode : null;
        const target = y.chargesVariables[op.key];
        const changes = {};
        if (v !== null) {
          // ── v13.9 : redistribution proportionnelle si details existent ──
          if (target.details && target.details.length > 0) {
            const currentSum = target.details.reduce((s, d) => s + (Number(d.montant) || 0), 0);
            if (currentSum === 0) {
              log.status = 'error';
              log.requires_redistribution = true;
              log.reason = 'Répartition proportionnelle impossible : toutes les sous-lignes sont à 0. Précise comment ventiler le nouveau total.';
              log.nouveau_total = v;
              log.lignes = target.details.map(d => ({ id: d.id, nom: d.nom, montant_actuel: d.montant }));
              break;
            }
            const ratio = v / currentSum;
            let distributed = 0;
            for (let i = 0; i < target.details.length - 1; i++) {
              const nm = Math.round(target.details[i].montant * ratio);
              target.details[i].montant = nm;
              distributed += nm;
            }
            target.details[target.details.length - 1].montant = v - distributed;
            changes.redistribution = { mode: 'proportionnelle', ratio: Math.round(ratio * 1000) / 1000, details_apres: target.details.map(d => ({ nom: d.nom, montant: d.montant })) };
          }
          changes.valeur = { avant: target.valeur, apres: v };
        }
        if (per !== null) { changes.periode = { avant: target.periode, apres: per }; target.periode = per; }
        if (lbl !== null) { changes.label = { avant: target.label, apres: lbl }; }
        if (Object.keys(changes).length === 0) { log.status = 'error'; log.reason = 'aucun champ à mettre à jour'; break; }
        writeCharge(target, v, lbl);
        log.key = op.key; log.changes = changes; break;
      }

      // ═══ ÉPARGNE ═══
      case 'set_epargne': {
        if (!y || !y.epargne || !y.epargne[op.key]) { log.status = 'skip'; log.reason = 'année ou clé absente'; break; }
        const v = pickNum(op, 'valeur', 'montant', 'value', 'amount');
        if (v === null) { log.status = 'error'; log.reason = 'aucune valeur numérique fournie'; break; }
        const old = y.epargne[op.key].valeur;
        writeEpargne(y.epargne[op.key], v, null);
        log.key = op.key; log.avant = old; log.apres = v; break;
      }
      case 'add_epargne': {
        if (!y) { log.status = 'skip'; log.reason = 'année absente'; break; }
        if (!y.epargne) y.epargne = {};
        if (y.epargne[op.key]) { log.status = 'skip'; log.reason = 'clé existe déjà — utilise update_epargne'; break; }
        const v = pickNum(op, 'valeur', 'montant', 'value', 'amount') ?? 0;
        const lbl = pickStr(op, 'label', 'nom') || op.key;
        y.epargne[op.key] = { label: lbl, valeur: v };
        log.key = op.key; log.created = true; log.valeur = v; break;
      }
      case 'remove_epargne': {
        if (!y || !y.epargne || !y.epargne[op.key]) { log.status = 'skip'; log.reason = 'clé absente'; break; }
        delete y.epargne[op.key]; log.key = op.key; log.removed = true; break;
      }
      case 'update_epargne': {
        if (!y || !y.epargne || !y.epargne[op.key]) { log.status = 'skip'; log.reason = 'clé absente'; break; }
        const v = pickNum(op, 'valeur', 'montant', 'value', 'amount');
        const lbl = pickStr(op, 'label', 'nom');
        const target = y.epargne[op.key];
        const changes = {};
        if (v !== null) { changes.valeur = { avant: target.valeur, apres: v }; }
        if (lbl !== null) { changes.label = { avant: target.label, apres: lbl }; }
        if (Object.keys(changes).length === 0) { log.status = 'error'; log.reason = 'aucun champ à mettre à jour'; break; }
        writeEpargne(target, v, lbl);
        log.key = op.key; log.changes = changes; break;
      }

      // ═══ DÉPENSES PONCTUELLES ═══
      case 'add_depense_ponctuelle': {
        if (!y) { log.status = 'skip'; log.reason = 'année absente'; break; }
        if (!Array.isArray(y.depensesIrregulieres)) y.depensesIrregulieres = [];
        const v = pickNum(op, 'montant', 'valeur', 'value', 'amount');
        if (v === null) { log.status = 'error'; log.reason = 'montant requis'; break; }
        const id = Date.now() + Math.floor(Math.random() * 1000);
        y.depensesIrregulieres.push({ id, mois: Number(op.mois), annee: a, nom: pickStr(op, 'nom', 'label') || 'Dépense', montant: v, paye: false, montantPaye: 0 });
        log.id = id; log.nom = op.nom; log.montant = v; break;
      }
      case 'remove_depense_ponctuelle': {
        if (!y) { log.status = 'skip'; log.reason = 'année absente'; break; }
        if (!Array.isArray(y.depensesIrregulieres)) y.depensesIrregulieres = [];
        const before = y.depensesIrregulieres.length;
        const byId = op.id != null;
        const byName = op.nom != null;
        y.depensesIrregulieres = y.depensesIrregulieres.filter(d => {
          if (byId && Number(d.id) === Number(op.id)) return false;
          if (byName && String(d.nom).toLowerCase().trim() === String(op.nom).toLowerCase().trim()) return false;
          return true;
        });
        log.critere = byId ? ('id=' + op.id) : ('nom=' + op.nom);
        log.supprimees = before - y.depensesIrregulieres.length; break;
      }
      case 'update_depense_ponctuelle': {
        if (!y || !Array.isArray(y.depensesIrregulieres)) { log.status = 'skip'; log.reason = 'année absente'; break; }
        const target = y.depensesIrregulieres.find(d => Number(d.id) === Number(op.id));
        if (!target) { log.status = 'skip'; log.reason = 'id introuvable'; break; }
        const v = pickNum(op, 'montant', 'valeur', 'value', 'amount');
        const changes = {};
        if (v !== null) { changes.montant = { avant: target.montant, apres: v }; target.montant = v; }
        if (op.mois != null) { changes.mois = { avant: target.mois, apres: Number(op.mois) }; target.mois = Number(op.mois); }
        if (op.annee != null) { changes.annee = { avant: target.annee, apres: Number(op.annee) }; target.annee = Number(op.annee); }
        if (op.nom != null) { changes.nom = { avant: target.nom, apres: String(op.nom) }; target.nom = String(op.nom); }
        // Purge synonymes parasites sur dépenses
        purgeKeys(target, SYN_NUM_DEPENSE);
        if (Object.keys(changes).length === 0) { log.status = 'error'; log.reason = 'aucun champ à mettre à jour'; break; }
        log.id = op.id; log.changes = changes; break;
      }

      // ═══ SOLDES INITIAUX ═══
      case 'set_solde_initial': {
        if (!financeData.soldesInitiaux) financeData.soldesInitiaux = {};
        const allowed = ['courant','urgence','lt','bourse','moisActuel','anneeActuelle','semainesRestantes'];
        if (!allowed.includes(op.key)) { log.status = 'error'; log.reason = 'clé non autorisée. Autorisées: ' + allowed.join(', '); break; }
        const v = pickNum(op, 'valeur', 'montant', 'value', 'amount');
        if (v === null) { log.status = 'error'; log.reason = 'aucune valeur numérique fournie'; break; }
        const old = financeData.soldesInitiaux[op.key];
        financeData.soldesInitiaux[op.key] = v;
        log.key = op.key; log.avant = old; log.apres = v; break;
      }

      // ═══ ANNÉES ═══
      case 'clone_annee': {
        const src = financeData.donneesAnnuelles && financeData.donneesAnnuelles[op.depuis];
        if (!src) { log.status = 'skip'; log.reason = 'année source absente'; break; }
        if (financeData.donneesAnnuelles[op.vers]) { log.status = 'skip'; log.reason = 'année cible existe déjà'; break; }
        const cloned = JSON.parse(JSON.stringify(src));
        Object.values(cloned.chargesFixes || {}).forEach(f => { f.paye = false; f.montantPaye = 0; });
        Object.values(cloned.chargesVariables || {}).forEach(c => { if (c.details) c.details.forEach(d => { d.paye = false; d.montantPaye = 0; }); });
        (cloned.depensesIrregulieres || []).forEach(d => { d.paye = false; d.montantPaye = 0; d.annee = Number(op.vers); d.id = Date.now() + Math.floor(Math.random() * 1000); });
        financeData.donneesAnnuelles[op.vers] = cloned;
        log.depuis = op.depuis; log.vers = op.vers; log.created = true; break;
      }
      case 'delete_annee': {
        if (!financeData.donneesAnnuelles[op.annee]) { log.status = 'skip'; log.reason = 'année absente'; break; }
        delete financeData.donneesAnnuelles[op.annee];
        log.annee = op.annee; log.removed = true; break;
      }

      // ═══ PROJET STUDIO ═══
      case 'set_projet_studio': {
        if (!y) { log.status = 'skip'; log.reason = 'année absente'; break; }
        if (!y.projetStudio) y.projetStudio = {};
        const allowed = ['prixM2','surface','avance','taux','duree','taxSyndic','taxCouvertCredit','surplusCredit','assuranceMensuelle','travaux','epargneDispo'];
        if (!allowed.includes(op.key)) { log.status = 'error'; log.reason = 'champ non autorisé. Autorisés: ' + allowed.join(', '); break; }
        const v = pickNum(op, 'valeur', 'montant', 'value', 'amount');
        if (v === null) { log.status = 'error'; log.reason = 'aucune valeur numérique fournie'; break; }
        const old = y.projetStudio[op.key];
        y.projetStudio[op.key] = v;
        log.key = op.key; log.avant = old; log.apres = v; break;
      }

      default:
        log.status = 'error';
        log.reason = "type d'opération INCONNU: '" + op.type + "'. Types valides : set/add/remove/rename/update_revenu, set/add/remove/rename/update_charge_fixe, set/add/remove/update_charge_variable, set_charge_variable_periode, set/add/remove/update_epargne, add/remove/update_depense_ponctuelle, set_solde_initial, clone_annee, delete_annee, set_projet_studio.";
    }
  } catch (e) {
    log.status = 'error'; log.reason = e.message;
  }
  return log;
}

// ═══ v13.21 : BATCH MULTI-ANNÉES ═══
const resultsByYear = {};
let allLogs = [];

for (const anneeTarget of annees) {
  const before = snapshot(financeData, anneeTarget);
  const log = [];
  for (const op of operations) {
    log.push(applyOp(financeData, op, anneeTarget));
  }
  const after = snapshot(financeData, anneeTarget);
  const sc = log.filter(l => l.status !== 'skip' && l.status !== 'error').length;
  const ec = log.filter(l => l.status === 'error').length;
  const sk = log.filter(l => l.status === 'skip').length;
  resultsByYear[anneeTarget] = {
    avant: before,
    apres: after,
    delta: before && after ? {
      revenus: after.revenus - before.revenus,
      fixes: after.fixes - before.fixes,
      variables: after.variables - before.variables,
      epargne: after.epargne - before.epargne
    } : null,
    ops_summary: { total: operations.length, success: sc, errors: ec, skipped: sk },
    operations_appliquees: log
  };
  allLogs = allLogs.concat(log);
}

// ⚠️ PASSE 2 : sanitize globale APRÈS toutes les ops (filet de sécurité)
const sanitize_report_post = sanitizeFinanceData(financeData);

const valid = financeData.donneesAnnuelles && typeof financeData.donneesAnnuelles === 'object' &&
              financeData.soldesInitiaux && typeof financeData.soldesInitiaux === 'object';

const successCount = allLogs.filter(l => l.status !== 'skip' && l.status !== 'error').length;
const errorCount   = allLogs.filter(l => l.status === 'error').length;
const skipCount    = allLogs.filter(l => l.status === 'skip').length;

const totalDirtPurged = Object.values(sanitize_report_pre).reduce((s, n) => s + n, 0)
                     + Object.values(sanitize_report_post).reduce((s, n) => s + n, 0);

// Si AUCUN op réussi MAIS du dirt a été nettoyé → on cache quand même la sanitize
const hasEffectiveChanges = (successCount > 0 && errorCount === 0) || (totalDirtPurged > 0 && errorCount === 0);

let pending_saved = false;
let pending_error = null;
if (simulate && valid && hasEffectiveChanges && session_id) {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://n8n.beau.ink/finance/pending_commit.php',
      body: {
        session_id,
        annee: isBatch ? annees : annees[0],
        operations,
        finance_data: financeData
      },
      json: true,
      timeout: 10000
    });
    pending_saved = !!(resp && resp.status === 'ok');
  } catch (e) {
    pending_error = e.message;
  }
}

// Retour consolidé : batch vs single-year (même interface backward-compat)
const firstYear = annees[0];
return JSON.stringify(isBatch ? {
  mode: simulate ? 'SIMULATION' : 'APPLY',
  valid,
  annees,
  batch: true,
  par_annee: resultsByYear,
  ops_summary_total: {
    total: operations.length * annees.length,
    success: successCount,
    errors: errorCount,
    skipped: skipCount
  },
  sanitize_report: {
    pre_ops: sanitize_report_pre,
    post_ops: sanitize_report_post,
    total_keys_purged: totalDirtPurged
  },
  pending_saved,
  pending_error,
  pending_session_id: session_id || null,
  warning: errorCount > 0 ? "Au moins une opération a échoué — pending NON sauvegardé. Vérifie par_annee, corrige et relance." : null,
  redistribution_required: allLogs.some(l => l.requires_redistribution) ? allLogs.filter(l => l.requires_redistribution) : null
} : {
  mode: simulate ? 'SIMULATION' : 'APPLY',
  valid,
  annee: firstYear,
  avant: resultsByYear[firstYear].avant,
  apres: resultsByYear[firstYear].apres,
  delta: resultsByYear[firstYear].delta,
  ops_summary: resultsByYear[firstYear].ops_summary,
  operations_appliquees: resultsByYear[firstYear].operations_appliquees,
  sanitize_report: {
    pre_ops: sanitize_report_pre,
    post_ops: sanitize_report_post,
    total_keys_purged: totalDirtPurged
  },
  pending_saved,
  pending_error,
  pending_session_id: session_id || null,
  warning: errorCount > 0 ? "Au moins une opération a échoué — pending NON sauvegardé. Vérifie operations_appliquees, corrige et relance." : null,
  redistribution_required: allLogs.some(l => l.requires_redistribution) ? allLogs.filter(l => l.requires_redistribution) : null
}, null, 2);

// ════════════════════════════════════════════════════════
// COMMITTER v4 (stateful) — lit pending_commit.php puis save_data.php
// FIX v13.5 : ne dépend PLUS de l'historique conversationnel.
// Workflow :
//   1. Vérifie confirmation === "OUI"
//   2. GET pending_commit.php?session_id=X
//   3. POST le finance_data récupéré vers save_data.php
//   4. DELETE pending_commit.php?session_id=X
// ════════════════════════════════════════════════════════
// ── v13.26 : ROBUST PARSING + DIAGNOSTICS (anti-silence) ─────────────
// REFONTE v13.26 : architecture robuste + diagnostique (plus jamais d'échec silencieux)
//
//  Couche 1 - PARSER MULTI-STRATEGIES :
//     Stratégie A : JSON.parse direct du query trim
//     Stratégie B : extraction d'un JSON object embarqué via regex (texte LLM verbeux)
//     Stratégie C : JSON scalar string ('"OUI"' -> "OUI")
//     Stratégie D : plain scalar ('OUI') -- UNIQUEMENT si l'outil l'autorise
//                   (committer oui, budget_engine non)
//
//  Couche 2 - PAS D'ECHEC SILENCIEUX :
//     Si parsing -> input vide, on retourne une erreur diagnostique
//     contenant raw_query, parse_strategy, et la liste des stratégies tentées.
//     -> permet de debug ce que Gemini envoie réellement.
//
//  Couche 3 - KWARGS TDZ-SAFE (v13.24 conservé) :
//     try/catch individuel par kwarg pour attraper ReferenceError + TDZ.
//
const TOOL_NAME = 'committer';
const ACCEPT_SCALAR = true;

let input = {};
let _parseStrategy = 'none';
let _rawQuery = null;
const _strategiesAttempted = [];

// Snapshot du query brut (pour diagnostic)
try {
  if (typeof query !== 'undefined' && query !== null) {
    _rawQuery = (typeof query === 'string') ? query : JSON.stringify(query);
  }
} catch (e) { _rawQuery = '<unstringifiable>'; }

// (A) Source primaire : query (multi-stratégies)
if (typeof query !== 'undefined' && query !== null) {
  if (typeof query === 'object') {
    input = Object.assign({}, query);
    _parseStrategy = 'object_direct';
  } else if (typeof query === 'string') {
    const trimmed = query.trim();

    // Stratégie A : JSON.parse direct
    _strategiesAttempted.push('A:json_parse');
    try {
      const parsedA = JSON.parse(trimmed);
      if (parsedA !== null && typeof parsedA === 'object' && !Array.isArray(parsedA)) {
        input = parsedA;
        _parseStrategy = 'A:json_object';
      } else if (typeof parsedA === 'string') {
        // JSON scalar '"OUI"' -> "OUI"
        if (ACCEPT_SCALAR) {
          input.confirmation = parsedA;
          _parseStrategy = 'C:json_scalar';
        }
      }
    } catch (eA) { /* pas du JSON pur */ }

    // Stratégie B : extraction d'un JSON object embarqué (LLM verbeux)
    if (_parseStrategy === 'none' && trimmed) {
      _strategiesAttempted.push('B:embedded_json');
      const m = trimmed.match(/\{[\s\S]*\}/);
      if (m) {
        try {
          const parsedB = JSON.parse(m[0]);
          if (parsedB && typeof parsedB === 'object' && !Array.isArray(parsedB)) {
            input = parsedB;
            _parseStrategy = 'B:json_embedded';
          }
        } catch (eB) { /* échec extraction */ }
      }
    }

    // Stratégie D : plain scalar (uniquement outils l'acceptant)
    if (_parseStrategy === 'none' && trimmed && ACCEPT_SCALAR) {
      _strategiesAttempted.push('D:plain_scalar');
      input.confirmation = trimmed;
      _parseStrategy = 'D:plain_scalar';
    }
  }
}

// (B) kwargs nommés (TDZ-safe, v13.24 conservé)
try { if (confirmation !== undefined && input.confirmation === undefined) input.confirmation = confirmation; } catch(e) {}
try { if (simulate     !== undefined && input.simulate     === undefined) input.simulate     = simulate;     } catch(e) {}
try { if (operations   !== undefined && input.operations   === undefined) input.operations   = operations;   } catch(e) {}
try { if (annee        !== undefined && input.annee        === undefined) input.annee        = annee;        } catch(e) {}
try { if (session_id   !== undefined && input.session_id   === undefined) input.session_id  = session_id;   } catch(e) {}

// COUCHE 2 : Diagnostic anti-silence
// Si parsing complètement raté ET pas de kwargs -> erreur explicite avec raw_query
if (Object.keys(input).length === 0) {
  return JSON.stringify({
    error: 'Aucun paramètre détecté (parsing query échoué, kwargs vides). Stratégies tentées: ' + _strategiesAttempted.join(', '),
    diagnostic: {
      tool: TOOL_NAME,
      raw_query: _rawQuery,
      query_type: typeof query,
      parse_strategy: _parseStrategy,
      strategies_attempted: _strategiesAttempted,
      hint: 'Gemini doit envoyer un JSON object { ... } dans query.'
    }
  });
}
// ──────────────────────────────────────────────────────────────────────────

// ── GARDE 1 : confirmation = "OUI" ──
if (!input.confirmation || String(input.confirmation).toUpperCase().trim() !== 'OUI') {
  return JSON.stringify({ error: 'REFUS : le paramètre confirmation doit être "OUI". Demande à l\'utilisateur de taper OUI.' });
}

// ── Récupère session_id depuis Build Agent Input (ou Normalize Input) ──
let session_id = null;
try { session_id = $('Build Agent Input').first().json.session_id; } catch (e) {}
if (!session_id) {
  try { session_id = $('Normalize Input').first().json.session_id; } catch (e) {}
}
if (!session_id) {
  return JSON.stringify({ error: 'session_id introuvable dans le contexte' });
}

// ── GARDE 2 : dernier message utilisateur contient "OUI" ──
let lastUserMsg = '';
try { lastUserMsg = String($('Normalize Input').first().json.question || '').toUpperCase(); } catch (e) {}
if (!/\bOUI\b|\bOK\b|\bVALIDE\b|\bGO\b/.test(lastUserMsg)) {
  return JSON.stringify({ error: 'REFUS : le dernier message utilisateur ne contient pas OUI/OK/VALIDE. Demande confirmation explicite.' });
}

const PENDING_URL = 'https://n8n.beau.ink/finance/pending_commit.php';
const SAVE_URL    = 'https://n8n.beau.ink/finance/save_data.php';

// ── 1. Récupère le pending depuis le cache serveur ──
let pending;
try {
  pending = await this.helpers.httpRequest({
    method: 'GET',
    url: PENDING_URL + '?session_id=' + encodeURIComponent(session_id),
    json: true,
    timeout: 10000
  });
} catch (e) {
  return JSON.stringify({
    error: 'Aucune simulation en attente. Demande à l\'utilisateur de reformuler sa modification (ex : "baisse le loyer à 4500"), je referai la simulation puis tu pourras valider par OUI.',
    detail: e.message,
    session_id
  });
}

if (!pending || !pending.finance_data || !pending.finance_data.donneesAnnuelles) {
  return JSON.stringify({
    error: 'Pending récupéré mais finance_data invalide. Demande à l\'utilisateur de relancer la simulation.',
    session_id,
    pending_keys: pending ? Object.keys(pending) : null
  });
}

const financeData = pending.finance_data;
const operations = pending.operations || [];
const annee = pending.annee;

// ── 2. POST vers save_data.php (commit officiel) ──
let saveResp;
try {
  saveResp = await this.helpers.httpRequest({
    method: 'POST',
    url: SAVE_URL,
    body: financeData,
    json: true,
    headers: { 'Content-Type': 'application/json' },
    timeout: 15000
  });
} catch (e) {
  return JSON.stringify({
    error: 'Échec écriture save_data.php',
    detail: e.message,
    session_id,
    pending_preserved: true
  });
}

// ── 3. DELETE pending (cleanup, idempotent) ──
let pendingDeleted = false;
try {
  const delResp = await this.helpers.httpRequest({
    method: 'DELETE',
    url: PENDING_URL + '?session_id=' + encodeURIComponent(session_id),
    json: true,
    timeout: 5000
  });
  pendingDeleted = !!(delResp && delResp.status === 'ok');
} catch (e) {
  // best effort, le pending expirera tout seul après 30 min
}

return JSON.stringify({
  status: 'ok',
  committed: true,
  session_id,
  annee,
  operations_count: operations.length,
  operations: operations,
  pending_deleted: pendingDeleted,
  server_response: saveResp
});

// ════════════════════════════════════════════════════════
// FORMAT FOR TELEGRAM v13.21.1 — Hotfix Unterminated group
// HOTFIX root cause : raw string Python introduisait 2 backslashes
//   devant / dans le litteral regex -> / terminait le litteral
//   -> pattern (<(?!\\ non ferme -> Unterminated group.
// Fix : new RegExp() pour le pattern strip-tags (pas de litteral regex /.../).
// ════════════════════════════════════════════════════════
let html = '';
let isError = false;
let errorDetail = '';

try {
  const agentOut = $('AI Agent').first().json;
  if (agentOut.error) {
    isError = true;
    errorDetail = typeof agentOut.error === 'string'
      ? agentOut.error
      : (agentOut.error.message || JSON.stringify(agentOut.error));
  } else {
    html = agentOut.output || agentOut.text || agentOut.response || '';
    if (!html) {
      isError = true;
      errorDetail = 'Aucune réponse générée (output vide après continueOnFail).';
    }
  }
} catch (e) {
  isError = true;
  errorDetail = e.message || 'Exception lors de la lecture de la sortie agent.';
}

if (isError) {
  const safeDetail = String(errorDetail)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
  return [{
    json: {
      telegram_text: '\u26a0\ufe0f <b>Alerte Syst\u00e8me (Super-Agent CFO)</b>\n'
        + 'Une exception a emp\u00each\u00e9 l\'ex\u00e9cution correcte de la commande.\n'
        + '<b>D\u00e9tail technique :</b> <code>' + safeDetail + '</code>',
      chat_id: $('Telegram Trigger').first().json.message.chat.id
    }
  }];
}

if (typeof html !== 'string') html = String(html);

// Regex pre-compilée hors littéral pour éviter le bug de terminaison /
// JS source : '<(?!/?(?:b|i|u|s|code|pre|a)\\b)[^>]+>'
// Dans le string literal JS, \\b = string value \b = RegExp word boundary
const STRIP_TAGS = new RegExp('<(?!/?(?:b|i|u|s|code|pre|a)\\b)[^>]+>', 'gi');

const text = html
  .replace(/<br\s*\/?>/gi, '\n')
  .replace(/<\/p>\s*<p[^>]*>/gi, '\n\n')
  .replace(/<\/?p[^>]*>/gi, '')
  .replace(/<\/li>/gi, '\n')
  .replace(/<li[^>]*>/gi, '\u2022 ')
  .replace(/<\/?ul[^>]*>/gi, '\n')
  .replace(/<\/?ol[^>]*>/gi, '\n')
  .replace(/<hr\s*\/?>/gi, '\n\u2014\u2014\u2014\n')
  .replace(/<\/?span[^>]*>/gi, '')
  .replace(/<\/?div[^>]*>/gi, '\n')
  .replace(/<strong>/gi, '<b>').replace(/<\/strong>/gi, '</b>')
  .replace(/<em>/gi, '<i>').replace(/<\/em>/gi, '</i>')
  .replace(STRIP_TAGS, '')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/&#39;/g, "'")
  .replace(/\n{3,}/g, '\n\n')
  .trim();

return [{
  json: {
    telegram_text: text,
    chat_id: $('Telegram Trigger').first().json.message.chat.id
  }
}];

// ════════════════════════════════════════════════════════
// MEMORY WRITER v1.4 — extraction depuis langage naturel
// v1.3 a prouve : query={} (Gemini envoie 0 arg car n8n ne lit pas le schema).
// v1.4 : on extrait le texte DIRECTEMENT de $json.question via regex.
//   L'agent n'a plus qu'a decider d'appeler l'outil.
//   L'outil parse seul. Aucun schema, aucun parametre attendu.
// ════════════════════════════════════════════════════════

// ── Helper : recherche cle dans n'importe quelle structure ───────────────────
function findKey(obj, key, depth) {
  if (depth === undefined) depth = 0;
  if (depth > 4 || obj === null || typeof obj !== 'object') return undefined;
  if (Array.isArray(obj)) {
    for (const item of obj) {
      const f = findKey(item, key, depth + 1);
      if (f !== undefined && f !== null && f !== '') return f;
    }
    return undefined;
  }
  if (key in obj && obj[key] !== null && obj[key] !== '') return obj[key];
  for (const k of Object.keys(obj)) {
    if (typeof obj[k] === 'object' && obj[k] !== null) {
      const f = findKey(obj[k], key, depth + 1);
      if (f !== undefined && f !== null && f !== '') return f;
    }
  }
  return undefined;
}

let _texte    = '';
let _categorie = 'general';
let _source   = null;

// ─────────────────────────────────────────────────────────────────────────────
// TENTATIVE 1 : Si Gemini envoie quand meme des params (cas chanceux)
// ─────────────────────────────────────────────────────────────────────────────
const sources = [];
try { if (typeof query !== 'undefined') sources.push({ n: 'query', v: query }); } catch (e) {}
try { if (typeof texte !== 'undefined') sources.push({ n: 'direct-vars', v: { texte, categorie: typeof categorie !== 'undefined' ? categorie : null } }); } catch (e) {}

for (const s of sources) {
  let val = s.v;
  if (typeof val === 'string') {
    try { val = JSON.parse(val); } catch (e) { /* string brute */
      if (val.length >= 5) { _texte = val.trim(); _source = s.n + '-string-direct'; }
      continue;
    }
  }
  const t = findKey(val, 'texte') || findKey(val, 'text');
  if (t && String(t).trim().length >= 5) {
    _texte = String(t).trim();
    const c = findKey(val, 'categorie') || findKey(val, 'category');
    if (c) _categorie = String(c).trim().toLowerCase();
    _source = s.n;
    break;
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// TENTATIVE 2 : Extraction depuis $json.question via REGEX (cas standard)
// ─────────────────────────────────────────────────────────────────────────────
let userQuestion = '';
if (!_texte || _texte.length < 5) {
  try { userQuestion = $('Build Agent Input').first().json.question || ''; } catch (e) {}
  if (!userQuestion) {
    try { userQuestion = $json.question || ''; } catch (e) {}
  }
  if (!userQuestion) {
    try { userQuestion = $('Normalize Input').first().json.question || ''; } catch (e) {}
  }

  if (userQuestion) {
    // Patterns ordonnes du plus specifique au plus general
    const patterns = [
      // "memorise cette information : XXX" (avec ou sans CFO devant)
      /(?:CFO[\s,]*)?(?:memorise|m[ée]morise|m[éeè]morise)[\s,]*cette\s+information[\s\:,]+(.+?)(?:[\.\!\?]?\s*$)/i,
      // "retiens (que/pour/cela) XXX"
      /(?:retiens|garde\s+en\s+m[ée]moire|note\s+(?:pour|que))\s*(?:que|pour\s+(?:le\s+)?futur|cela)?\s*[:,]?\s*(.+?)(?:[\.\!\?]?\s*$)/i,
      // "souviens-toi (que) XXX"
      /souviens[\s\-]toi\s*(?:que|de|du|des)?\s*[:,]?\s*(.+?)(?:[\.\!\?]?\s*$)/i,
      // "memorise XXX" simple (en dernier car plus permissif)
      /(?:CFO[\s,]*)?(?:memorise|m[ée]morise|m[éeè]morise)\s*(?:que)?\s*[:,]?\s*(.+?)(?:[\.\!\?]?\s*$)/i,
    ];

    for (const p of patterns) {
      const m = userQuestion.match(p);
      if (m && m[1]) {
        let extracted = m[1].trim();
        // Nettoyage : supprime ponctuation finale et espaces
        extracted = extracted.replace(/[\.\!\?\s]+$/, '').trim();
        if (extracted.length >= 5) {
          _texte = extracted;
          _source = 'question-regex';
          break;
        }
      }
    }
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// TENTATIVE 3 : Inference de categorie depuis le contenu du texte
// ─────────────────────────────────────────────────────────────────────────────
if (_texte && _categorie === 'general') {
  const lower = _texte.toLowerCase();
  if (/\b(je\s+pr[ée]f[èe]re|j['']aime|habituellement|toujours|jamais)\b/.test(lower)) {
    _categorie = 'preference';
  } else if (/\b(plafond|max(?:imum)?|limite|jamais\s+(?:plus|moins)|r[èe]gle)\b/.test(lower)) {
    _categorie = 'regle';
  } else if (/\b(actuellement|en\s+ce\s+moment|cette\s+ann[ée]e|jusqu['']en)\b/.test(lower)) {
    _categorie = 'contexte';
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// Validation
// ─────────────────────────────────────────────────────────────────────────────
const VALID_CATS = ['preference', 'regle', 'contexte', 'general'];
if (!VALID_CATS.includes(_categorie)) _categorie = 'general';

if (!_texte || _texte.length < 5) {
  return JSON.stringify({
    error: 'INPUT_INVALIDE',
    raison: 'Aucune source ni regex n a trouve de texte a memoriser.',
    user_question_recu: userQuestion ? userQuestion.slice(0, 200) : '(vide)',
    user_question_length: userQuestion ? userQuestion.length : 0,
    sources_disponibles: sources.length,
    cause_probable: 'La question utilisateur ne contient pas de pattern de memorisation reconnu (retiens que / memorise / souviens-toi). Demander a l utilisateur de reformuler.'
  });
}

// ─────────────────────────────────────────────────────────────────────────────
// session_id
// ─────────────────────────────────────────────────────────────────────────────
let session_id = null;
try { session_id = $('Build Agent Input').first().json.session_id; } catch (e) {}
if (!session_id) {
  try { session_id = $('Normalize Input').first().json.session_id; } catch (e) {}
}

// ─────────────────────────────────────────────────────────────────────────────
// Appel sous-workflow d'ingestion
// ─────────────────────────────────────────────────────────────────────────────
const WEBHOOK_URL = 'https://n8n.beau.ink/webhook/finance-memory-ingest';
const requestBody = { texte: _texte, categorie: _categorie, session_id: session_id || 'unknown' };

try {
  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url: WEBHOOK_URL,
    body: requestBody,
    json: true,
    timeout: 20000
  });

  if (resp && resp.status === 'ok') {
    return JSON.stringify({
      status: 'ok',
      memorise: true,
      texte: _texte,
      categorie: _categorie,
      input_source: _source,
      message: 'Information enregistree dans la memoire long terme. Disponible dans toutes les sessions futures via finance_rag.'
    });
  }
  return JSON.stringify({
    error: 'INGESTION_REPONSE_KO',
    raison: 'Sous-workflow a repondu sans status=ok',
    response_recue: resp,
    request_envoyee: requestBody
  });

} catch (e) {
  const errInfo = {
    error: 'WEBHOOK_ECHEC',
    e_message: e && e.message ? e.message : null,
    e_statusCode: (e && (e.statusCode || e.code)) || null,
    request_envoyee: requestBody,
    cause_probable: null
  };
  if (errInfo.e_statusCode === 404) errInfo.cause_probable = 'Sous-workflow CFO Memory Ingest non ACTIVE';
  else if (errInfo.e_statusCode === 500) errInfo.cause_probable = 'Sous-workflow leve une exception';
  else if (/ECONNREFUSED|ENOTFOUND|timeout/i.test(errInfo.e_message || '')) errInfo.cause_probable = 'Reseau / DNS / timeout';
  return JSON.stringify(errInfo);
}

// ════════════════════════════════════════════════════════
// INTENT COMPILER v1.0 — Super-Agent CFO v14.0
// Architecture NLU -> Compiler -> Apply
//
// Interface Gemini (simple, sans types techniques) :
//   { "changes": [{ action, category, target, amount, years, ... }] }
//
// Pipeline interne :
//   1. Parse input (multi-strategy)
//   2. Valide et résout chaque change (fuzzy match target -> key)
//   3. Si clarification nécessaire : retourne sans appliquer
//   4. Capture snapshot "avant" par année
//   5. Construit les ops canoniques et les applique inline
//   6. Capture snapshot "après" et calcule delta
//   7. Sauvegarde pending_commit
// ════════════════════════════════════════════════════════

const TOOL_NAME = 'propose_changes';

// ── Multi-strategy parser (défense en profondeur) ──────
let input = {};
let _parseStrategy = 'none';
let _rawQuery = null;
const _strategiesAttempted = [];

try {
  if (typeof query !== 'undefined' && query !== null) {
    _rawQuery = typeof query === 'string' ? query : JSON.stringify(query);
  }
} catch (e) { _rawQuery = '<unstringifiable>'; }

if (typeof query !== 'undefined' && query !== null) {
  if (typeof query === 'object') {
    input = Object.assign({}, query);
    _parseStrategy = 'object_direct';
  } else if (typeof query === 'string') {
    const trimmed = query.trim();
    _strategiesAttempted.push('A:json_parse');
    try {
      const parsedA = JSON.parse(trimmed);
      if (parsedA && typeof parsedA === 'object' && !Array.isArray(parsedA)) {
        input = parsedA; _parseStrategy = 'A:json_object';
      }
    } catch (eA) {}
    if (_parseStrategy === 'none' && trimmed) {
      _strategiesAttempted.push('B:embedded_json');
      const m = trimmed.match(/\{[\s\S]*\}/);
      if (m) {
        try {
          const parsedB = JSON.parse(m[0]);
          if (parsedB && typeof parsedB === 'object' && !Array.isArray(parsedB)) {
            input = parsedB; _parseStrategy = 'B:json_embedded';
          }
        } catch (eB) {}
      }
    }
  }
}

// kwargs TDZ-safe
try { if (typeof changes !== 'undefined' && input.changes === undefined) input.changes = changes; } catch(e) {}

if (!input.changes || !Array.isArray(input.changes) || !input.changes.length) {
  return JSON.stringify({
    error: 'Paramètre "changes" manquant ou vide. Format : { "changes": [{ action, category, target, years, ... }] }',
    diagnostic: { tool: TOOL_NAME, raw_query: _rawQuery, parse_strategy: _parseStrategy, strategies_attempted: _strategiesAttempted }
  });
}

// ── Contexte ──────────────────────────────────────────
let normalized;
try { normalized = $('Build Agent Input').first().json; }
catch (e) {
  try { normalized = $('Normalize Input').first().json; }
  catch (e2) { return JSON.stringify({ error: 'Contexte introuvable (Build Agent Input / Normalize Input)' }); }
}
const session_id = normalized.session_id;
// v20.80 : prefer finance_data_raw (full VPS JSON with donneesAnnuelles) over sanitized payload v20.31
const _rawSrcIntent = normalized.finance_data_raw || normalized.finance_data;
const financeData = _rawSrcIntent ? JSON.parse(JSON.stringify(_rawSrcIntent)) : null;
if (!financeData) return JSON.stringify({ error: 'finance_data absent. Recharge l\'interface web.' });

// ════════════════════════════════════════════════════════
// HELPERS (portés du Budget Engine v6/v13.9)
// ════════════════════════════════════════════════════════
const pickNum = (op, ...keys) => {
  for (const k of keys) {
    if (op[k] !== undefined && op[k] !== null && op[k] !== '') {
      const n = Number(op[k]); if (Number.isFinite(n)) return n;
    }
  }
  return null;
};
const pickStr = (op, ...keys) => {
  for (const k of keys) { if (op[k] !== undefined && op[k] !== null) return String(op[k]); }
  return null;
};

const SYN_NUM_CHARGE  = ['montant', 'value', 'amount'];
const SYN_NUM_REVENU  = ['valeur', 'montant', 'value', 'amount', 'salaire'];
const SYN_NUM_DEPENSE = ['valeur', 'value', 'amount'];
const SYN_LBL         = ['nom'];

const purgeKeys = (obj, syns) => {
  let p = 0;
  if (!obj || typeof obj !== 'object') return 0;
  for (const s of syns) { if (Object.prototype.hasOwnProperty.call(obj, s)) { delete obj[s]; p++; } }
  return p;
};

function sanitizeFinanceData(fd) {
  const r = { revenus: 0, fixes: 0, variables: 0, epargne: 0, depenses: 0 };
  if (!fd || !fd.donneesAnnuelles) return r;
  for (const yr in fd.donneesAnnuelles) {
    const y = fd.donneesAnnuelles[yr]; if (!y) continue;
    for (const k in (y.revenus || {})) {
      const o = y.revenus[k]; if (!o) continue;
      if (o.base == null) { const rv = pickNum(o, 'valeur', 'montant', 'value', 'amount', 'salaire'); if (rv !== null) o.base = rv; }
      if (o.label == null && o.nom) o.label = String(o.nom);
      r.revenus += purgeKeys(o, SYN_NUM_REVENU) + purgeKeys(o, SYN_LBL);
    }
    for (const k in (y.chargesFixes || {})) {
      const o = y.chargesFixes[k]; if (!o) continue;
      if (o.valeur == null) { const rv = pickNum(o, 'montant', 'value', 'amount'); if (rv !== null) o.valeur = rv; }
      if (o.label == null && o.nom) o.label = String(o.nom);
      r.fixes += purgeKeys(o, SYN_NUM_CHARGE) + purgeKeys(o, SYN_LBL);
    }
    for (const k in (y.chargesVariables || {})) {
      const o = y.chargesVariables[k]; if (!o) continue;
      if (o.valeur == null) { const rv = pickNum(o, 'montant', 'value', 'amount'); if (rv !== null) o.valeur = rv; }
      if (o.label == null && o.nom) o.label = String(o.nom);
      r.variables += purgeKeys(o, SYN_NUM_CHARGE) + purgeKeys(o, SYN_LBL);
    }
    // v20.90 : epargne peut etre array (Vue.js v17.99) OU legacy object — itere les deux
    const _epPool = Array.isArray(y.epargne) ? y.epargne.filter(Boolean) : Object.values(y.epargne || {}).filter(Boolean);
    for (const o of _epPool) {
      if (o.valeur == null) { const rv = pickNum(o, 'montant', 'value', 'amount'); if (rv !== null) o.valeur = rv; }
      if (o.label == null && o.nom) o.label = String(o.nom);
      if (o.nom == null && o.label) o.nom = String(o.label);
      r.epargne += purgeKeys(o, SYN_NUM_CHARGE) + purgeKeys(o, SYN_LBL);
    }
    for (const d of (y.depensesIrregulieres || [])) {
      if (!d) continue;
      if (d.montant == null) { const rv = pickNum(d, 'valeur', 'value', 'amount'); if (rv !== null) d.montant = rv; }
      r.depenses += purgeKeys(d, SYN_NUM_DEPENSE);
    }
  }
  return r;
}

const writeCharge = (t, v, l) => { if (v != null) t.valeur = v; if (l != null) t.label = l; purgeKeys(t, SYN_NUM_CHARGE); purgeKeys(t, SYN_LBL); };
const writeRevenu  = (t, b, l) => { if (b != null) t.base  = b; if (l != null) t.label = l; purgeKeys(t, SYN_NUM_REVENU);  purgeKeys(t, SYN_LBL); };
const writeEpargne = (t, v, l) => { if (v != null) t.valeur = v; if (l != null) t.label = l; purgeKeys(t, SYN_NUM_CHARGE); purgeKeys(t, SYN_LBL); };

const snapshot = (fd, yr) => {
  const y = fd.donneesAnnuelles && fd.donneesAnnuelles[yr];
  if (!y) return null;
  const sum = obj => Object.values(obj || {}).reduce((s, v) => s + (Number(v && v.valeur) || Number(v && v.base) || 0), 0);
  return { revenus: sum(y.revenus), fixes: sum(y.chargesFixes), variables: sum(y.chargesVariables), epargne: sum(y.epargne), depensesIrreg: (y.depensesIrregulieres || []).length };
};

// ════════════════════════════════════════════════════════
// ENTITY RESOLVER — fuzzy match target label -> key technique
// ════════════════════════════════════════════════════════
function normStr(s) {
  return String(s || '').toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, ' ').trim();
}

function levenshtein(a, b) {
  const m = a.length, n = b.length;
  const dp = [];
  for (let i = 0; i <= m; i++) { dp[i] = [i]; for (let j = 1; j <= n; j++) dp[i][j] = 0; }
  for (let j = 0; j <= n; j++) dp[0][j] = j;
  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      dp[i][j] = a[i-1] === b[j-1] ? dp[i-1][j-1] : 1 + Math.min(dp[i-1][j], dp[i][j-1], dp[i-1][j-1]);
    }
  }
  return dp[m][n];
}

const POOL_MAP = { revenu: 'revenus', charge_fixe: 'chargesFixes', charge_variable: 'chargesVariables', epargne: 'epargne' };

function resolveEntity(target, category, fd) {
  const normT = normStr(target);
  const candidates = [];
  const seen = new Set();

  const catKeys = category && POOL_MAP[category] ? [category] : Object.keys(POOL_MAP);

  for (const yr in fd.donneesAnnuelles) {
    const y = fd.donneesAnnuelles[yr]; if (!y) continue;
    for (const cat of catKeys) {
      const rawPool = y[POOL_MAP[cat]] || {};
      // v20.90 : epargne v17.99 = array d'objets {id, nom, ...} → cle technique = 'ep_'+id
      const pool = Array.isArray(rawPool)
        ? Object.fromEntries(rawPool.filter(Boolean).map(item => ['ep_' + (item.id || ''), item]))
        : rawPool;
      for (const key in pool) {
        const dk = cat + ':' + key;
        if (seen.has(dk)) continue; seen.add(dk);
        const item = pool[key];
        const lbl = item.label || item.nom || key;
        const normL = normStr(lbl), normK = normStr(key);
        const dist = Math.min(levenshtein(normT, normL), levenshtein(normT, normK));
        const contains = normL.includes(normT) || normK.includes(normT) || normT.includes(normL) || normT.includes(normK);
        candidates.push({ key, label: lbl, category: cat, dist, contains });
      }
    }
  }

  // Soldes initiaux
  if (!category || category === 'solde') {
    for (const key in (fd.soldesInitiaux || {})) {
      const dk = 'solde:' + key;
      if (seen.has(dk)) continue; seen.add(dk);
      const normK = normStr(key);
      const dist = levenshtein(normT, normK);
      const contains = normK.includes(normT) || normT.includes(normK);
      candidates.push({ key, label: key, category: 'solde', dist, contains });
    }
  }

  if (!candidates.length) {
    return { resolved: false, error: '"' + target + '" introuvable' + (category ? ' dans ' + category : '') + '. Finance data vide ou catégorie incorrecte.' };
  }

  candidates.sort((a, b) => {
    if (a.contains !== b.contains) return a.contains ? -1 : 1;
    return a.dist - b.dist;
  });

  const best = candidates[0];
  const second = candidates[1];
  const thresh = Math.max(4, Math.floor(normT.length * 0.55));

  // Ambiguïté : deux candidats "contains" avec même distance
  if (second && second.contains && best.contains && best.key !== second.key && best.dist === second.dist && best.category === second.category) {
    return { resolved: false, ambiguous: true, choices: [best, second],
      error: '"' + target + '" est ambigu. Précise : "' + best.label + '" (' + best.key + ') ou "' + second.label + '" (' + second.key + ') ?' };
  }

  // Distance trop grande sans "contains"
  if (!best.contains && best.dist > thresh) {
    const sugg = candidates.slice(0, 4).map(c => '"' + c.label + '"').join(', ');
    return { resolved: false, error: '"' + target + '" ne correspond à aucune ligne connue. Lignes proches : ' + sugg };
  }

  return { resolved: true, key: best.key, label: best.label, category: best.category };
}

// ════════════════════════════════════════════════════════
// OP BUILDER — (action, category, resolvedKey) -> op[]
// Gemini ne voit JAMAIS les types techniques — c'est ici qu'ils sont déterminés.
// ════════════════════════════════════════════════════════
function buildOps(change, resolvedKey, resolvedCat, annee) {
  const { action, amount, label: newLabel, period, month, exception_start, exception_end, exception_value, exception_id, clone_from_year, studio_key, balance_key, one_off_id, target, sub_target: subTarget } = change;
  const amt = (amount !== undefined && amount !== null && !isNaN(Number(amount))) ? Number(amount) : null;
  // v15.14 — Multi-Add Key Collision fix : suffixe aléatoire pour les ops 'add'
  // garantit l'unicité de la clé technique même si l'IA ajoute 3 fois le même label
  const safeTarget = String(target || newLabel || 'nouvelle_ligne').replace(/\s+/g, '_').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  const baseKey = resolvedKey || (action === 'add' ? safeTarget + '_' + Math.random().toString(36).substring(2, 6) : safeTarget);

  switch (action) {
    case 'modify':
      switch (resolvedCat) {
        case 'revenu':         return [{ type: 'update_revenu',         key: resolvedKey, ...(amt != null && { base: amt }),   ...(newLabel && { label: newLabel }) }];
        case 'charge_fixe':    return [{ type: 'update_charge_fixe',    key: resolvedKey, ...(amt != null && { valeur: amt }), ...(newLabel && { label: newLabel }) }];
        case 'charge_variable':
          if (subTarget) return [{ type: 'update_charge_variable_detail', key: resolvedKey, sub_key: subTarget, montant: amt }];
          return [{ type: 'update_charge_variable', key: resolvedKey, ...(amt != null && { valeur: amt }), ...(period && { periode: period }), ...(newLabel && { label: newLabel }) }];
        case 'epargne':        return [{ type: 'update_epargne',        key: resolvedKey, ...(amt != null && { valeur: amt }), ...(newLabel && { label: newLabel }) }];
        case 'studio':         return [{ type: 'set_projet_studio', annee, key: studio_key || resolvedKey || 'travaux', valeur: amt }];
        case 'solde':          return [{ type: 'set_solde_initial', key: balance_key || resolvedKey || 'courant', valeur: amt }];
        case 'compte':         return [{ type: 'update_compte', key: change.target_key || target, montant: amt }];
        case 'objectif':       return [{ type: 'update_objectif', key: change.target_key || target, montant: amt }];
        case 'actif':
        case 'foncier':        return [{ type: 'update_master_asset', key: change.target_key || target, montant: amt, ...(subTarget && { scenario: subTarget }), ...(change.sous_categorie && { scenario: change.sous_categorie }), ...(change.taux_credit !== undefined && { taux_credit: change.taux_credit }), ...(change.annees_total !== undefined && { annees_total: change.annees_total }), ...(change.annees_restantes !== undefined && { annees_restantes: change.annees_restantes }), ...(change.apport_personnel !== undefined && { apport_personnel: change.apport_personnel }), ...(change.montant_credit !== undefined && { montant_credit: change.montant_credit }), ...(change.valeur_actuelle !== undefined && { valeur_actuelle: change.valeur_actuelle }) }];
        default: return null;
      }
    case 'add':
      switch (resolvedCat) {
        case 'revenu':          return [{ type: 'add_revenu',         key: baseKey, label: newLabel || target, base: amt || 0 }];
        case 'charge_fixe':     return [{ type: 'add_charge_fixe',    key: baseKey, label: newLabel || target, valeur: amt || 0 }];
        case 'charge_variable': return [{ type: 'add_charge_variable',key: baseKey, label: newLabel || target, valeur: amt || 0, periode: period || 'mois' }];
        case 'epargne':         return [{ type: 'add_epargne',        key: baseKey, label: newLabel || target, valeur: amt || 0 }];
        case 'depense_ponctuelle': return [{ type: 'add_depense_ponctuelle', annee, mois: month || 1, nom: newLabel || target, montant: amt || 0 }];
        case 'compte':         return [{ type: 'create_compte', label: newLabel || target, montant: amt || 0 }];
        case 'objectif':       return [{ type: 'create_objectif', name: newLabel || target, current: amt || 0, target_amount: change.target_amount || 0 }];
        default: return null;
      }
    case 'remove':
      switch (resolvedCat) {
        case 'revenu':          return [{ type: 'remove_revenu',         key: resolvedKey }];
        case 'charge_fixe':     return [{ type: 'remove_charge_fixe',    key: resolvedKey }];
        case 'charge_variable': return [{ type: 'remove_charge_variable',key: resolvedKey }];
        case 'epargne':         return [{ type: 'remove_epargne',        key: resolvedKey }];
        case 'depense_ponctuelle': return one_off_id ? [{ type: 'remove_depense_ponctuelle', annee, id: one_off_id }] : [{ type: 'remove_depense_ponctuelle', annee, nom: target }];
        case 'annee':           return [{ type: 'delete_annee', annee }];
        default: return null;
      }
    case 'rename':
      if (!newLabel) return null;
      switch (resolvedCat) {
        case 'revenu':      return [{ type: 'rename_revenu',      key: resolvedKey, label: newLabel }];
        case 'charge_fixe': return [{ type: 'rename_charge_fixe', key: resolvedKey, label: newLabel }];
        default: return null;
      }
    case 'add_exception':
      switch (resolvedCat) {
        case 'revenu':      return [{ type: 'add_revenu_exception',     key: resolvedKey, moisDebut: exception_start, moisFin: exception_end, nouvelleValeur: exception_value }];
        case 'charge_fixe': return [{ type: 'add_charge_fixe_exception',key: resolvedKey, moisDebut: exception_start, moisFin: exception_end, nouvelleValeur: exception_value }];
        case 'epargne':     return [{ type: 'add_epargne_exception',    key: resolvedKey || target, moisDebut: exception_start, moisFin: exception_end, nouvelleValeur: exception_value }];
        default: return null;
      }
    case 'remove_exception':
      switch (resolvedCat) {
        case 'revenu':      return [{ type: 'remove_revenu_exception',     key: resolvedKey, id: exception_id }];
        case 'charge_fixe': return [{ type: 'remove_charge_fixe_exception',key: resolvedKey, id: exception_id }];
        case 'epargne':     return [{ type: 'remove_epargne_exception',    key: resolvedKey || target, id: exception_id }];
        default: return null;
      }
    case 'update_one_off':
      return one_off_id ? [{ type: 'update_depense_ponctuelle', id: one_off_id, ...(amt != null && { montant: amt }), ...(month && { mois: month }), ...(newLabel && { nom: newLabel }) }] : null;
    case 'clone_year':
      return [{ type: 'clone_annee', depuis: clone_from_year || (annee - 1), vers: annee }];
    case 'set_balance':
      return [{ type: 'set_solde_initial', key: balance_key || baseKey, valeur: amt }];
    case 'set_studio':
      return [{ type: 'set_projet_studio', annee, key: studio_key || baseKey, valeur: amt }];
    default: return null;
  }
}

// ════════════════════════════════════════════════════════
// applyOp — inline depuis Budget Engine v6/v13.9 (logique identique)
// ════════════════════════════════════════════════════════
function applyOp(fd, op, anneeTarget) {
  const a = Number(op.annee || anneeTarget);
  const y = fd.donneesAnnuelles && fd.donneesAnnuelles[a];
  const log = { op: op.type };
  try {
    switch (op.type) {
      // ── REVENUS ────────────────────────────────────────
      case 'set_revenu': {
        if (!y || !y.revenus || !y.revenus[op.key]) { log.status='skip'; log.reason='clé absente'; break; }
        const v = pickNum(op, 'base', 'valeur', 'montant', 'value', 'amount', 'salaire');
        if (v === null) { log.status='error'; log.reason='valeur manquante'; break; }
        const old = y.revenus[op.key].base; writeRevenu(y.revenus[op.key], v, null);
        log.key=op.key; log.avant=old; log.apres=v; break;
      }
      case 'add_revenu': {
        if (!y) { log.status='skip'; log.reason='année absente'; break; }
        if (!y.revenus) y.revenus={};
        if (y.revenus[op.key]) { log.status='skip'; log.reason='clé existe déjà'; break; }
        const v = pickNum(op, 'base', 'valeur', 'montant', 'value', 'amount', 'salaire') ?? 0;
        const lbl = pickStr(op, 'label', 'nom') || op.key;
        y.revenus[op.key] = { label: lbl, base: v, showExceptions: false, exceptions: [] };
        log.key=op.key; log.created=true; log.base=v; break;
      }
      case 'remove_revenu': {
        if (!y || !y.revenus || !y.revenus[op.key]) { log.status='skip'; log.reason='clé absente'; break; }
        delete y.revenus[op.key]; log.key=op.key; log.removed=true; break;
      }
      case 'rename_revenu': {
        if (!y || !y.revenus || !y.revenus[op.key]) { log.status='skip'; log.reason='clé absente'; break; }
        const lbl = pickStr(op, 'label', 'nom');
        if (!lbl) { log.status='error'; log.reason='label manquant'; break; }
        const old = y.revenus[op.key].label; writeRevenu(y.revenus[op.key], null, lbl);
        log.key=op.key; log.avant=old; log.apres=lbl; break;
      }
      case 'update_revenu': {
        if (!y || !y.revenus || !y.revenus[op.key]) { log.status='skip'; log.reason='clé absente'; break; }
        const v = pickNum(op, 'base', 'valeur', 'montant', 'value', 'amount', 'salaire');
        const lbl = pickStr(op, 'label', 'nom');
        const t = y.revenus[op.key]; const ch = {};
        if (v !== null) ch.base = { avant: t.base, apres: v };
        if (lbl !== null) ch.label = { avant: t.label, apres: lbl };
        if (!Object.keys(ch).length) { log.status='error'; log.reason='aucun champ fourni'; break; }
        writeRevenu(t, v, lbl); log.key=op.key; log.changes=ch; break;
      }
      case 'add_revenu_exception': {
        if (!y || !y.revenus || !y.revenus[op.key]) { log.status='skip'; log.reason='clé absente'; break; }
        if (!Array.isArray(y.revenus[op.key].exceptions)) y.revenus[op.key].exceptions=[];
        const id = Date.now()+Math.floor(Math.random()*1000);
        y.revenus[op.key].exceptions.push({ id, moisDebut:Number(op.moisDebut), moisFin:Number(op.moisFin), nouvelleValeur:Number(op.nouvelleValeur) });
        y.revenus[op.key].showExceptions=true; log.key=op.key; log.id=id; break;
      }
      case 'remove_revenu_exception': {
        if (!y || !y.revenus || !y.revenus[op.key]) { log.status='skip'; log.reason='clé absente'; break; }
        const before=(y.revenus[op.key].exceptions||[]).length;
        y.revenus[op.key].exceptions=(y.revenus[op.key].exceptions||[]).filter(e=>Number(e.id)!==Number(op.id));
        log.key=op.key; log.supprimees=before-y.revenus[op.key].exceptions.length; break;
      }
