const TOOL_NAME = 'transactions_reelles_engine';
const ACCEPT_SCALAR = false;

let input = {};
let _parseStrategy = 'none';
let _rawQuery = null;
const _strategiesAttempted = [];

try { if (typeof query !== 'undefined' && query !== null) _rawQuery = (typeof query === 'string') ? query : JSON.stringify(query); }
catch (e) { _rawQuery = '<unstringifiable>'; }

if (typeof query !== 'undefined' && query !== null) {
  if (typeof query === 'object') {
    input = Object.assign({}, query);
    _parseStrategy = 'object_direct';
  } else if (typeof query === 'string') {
    const trimmed = query.trim();
    _strategiesAttempted.push('A:json_parse');
    try {
      const parsedA = JSON.parse(trimmed);
      if (parsedA !== null && typeof parsedA === 'object' && !Array.isArray(parsedA)) {
        input = parsedA;
        _parseStrategy = 'A:json_object';
      }
    } catch (eA) {}
    if (_parseStrategy === 'none' && trimmed) {
      _strategiesAttempted.push('B:embedded_json');
      const m = trimmed.match(/\{[\s\S]*\}/);
      if (m) {
        try {
          const parsedB = JSON.parse(m[0]);
          if (parsedB && typeof parsedB === 'object' && !Array.isArray(parsedB)) {
            input = parsedB;
            _parseStrategy = 'B:json_embedded';
          }
        } catch (eB) {}
      }
    }
  }
}

try { if (action      !== undefined && input.action      === undefined) input.action      = action; }      catch(e) {}
try { if (operations  !== undefined && input.operations  === undefined) input.operations  = operations; }  catch(e) {}
try { if (transaction !== undefined && input.transaction === undefined) input.transaction = transaction; } catch(e) {}
try { if (id          !== undefined && input.id          === undefined) input.id          = id; }          catch(e) {}
try { if (annee       !== undefined && input.annee       === undefined) input.annee       = annee; }       catch(e) {}
try { if (mois        !== undefined && input.mois        === undefined) input.mois        = mois; }        catch(e) {}

if (Object.keys(input).length === 0) {
  return JSON.stringify({
    error: 'Aucun paramètre détecté.',
    diagnostic: { tool: TOOL_NAME, raw_query: _rawQuery, parse_strategy: _parseStrategy, strategies_attempted: _strategiesAttempted }
  });
}

