let normalized;
try { normalized = $('Build Agent Input').first().json; }
catch (e) {
  try { normalized = $('Normalize Input').first().json; }
  catch (e2) { return JSON.stringify({ error: 'Contexte introuvable' }); }
}
const session_id = normalized.session_id;
const _src = normalized.finance_data_raw || normalized.finance_data;
const fd = _src ? JSON.parse(JSON.stringify(_src)) : null;

if (!fd) return JSON.stringify({ error: 'Aucun finance_data dans la requête.' });

// ── Helpers ──
const today = new Date();
const pad = n => String(n).padStart(2, '0');
const todayDate = today.getFullYear() + '-' + pad(today.getMonth() + 1) + '-' + pad(today.getDate());
const currentAnnee = today.getFullYear();
const currentMois = today.getMonth() + 1;

const pickNum = (op, ...keys) => {
  for (const k of keys) {
    if (op[k] !== undefined && op[k] !== null && op[k] !== '') {
      const n = Number(op[k]);
      if (Number.isFinite(n)) return n;
    }
  }
  return null;
};
const pickStr = (op, ...keys) => {
  for (const k of keys) {
    if (op[k] !== undefined && op[k] !== null) return String(op[k]).trim();
  }
  return null;
};

function resolveCategorieId(rawInput, fd) {
  if (!rawInput) return 'cat_misc';
  const s = String(rawInput).toLowerCase().trim();
  if (!s) return 'cat_misc';
  if (s.startsWith('cat_')) return s;
  const cats = ((fd.soldesInitiaux && fd.soldesInitiaux.categories) || []).filter(c => c && !c.archive);
  // 1. Match exact label
  for (const c of cats) {
    if (String(c.label || '').toLowerCase() === s) return c.id;
  }
  // 2. Match mot-par-mot (tokenisation)
  const targetWords = s.split(/[\s,;.()\-_/&]+/).filter(w => w.length >= 3);
  for (const c of cats) {
    const lab = String(c.label || '').toLowerCase().trim();
    if (!lab) continue;
    const labWords = lab.split(/[\s,;.()\-_/&]+/).filter(w => w.length >= 3);
    for (const tw of targetWords) {
      for (const lw of labWords) {
        if (tw === lw) return c.id;
        if (tw.length >= 4 && lw.includes(tw)) return c.id;
        if (lw.length >= 4 && tw.includes(lw)) return c.id;
      }
    }
  }
  return 'cat_misc';
}

function resolveCompteId(rawInput, fd) {
  if (rawInput === null || rawInput === undefined || rawInput === '') return null;
  if (typeof rawInput === 'number') return rawInput;
  const s = String(rawInput).toLowerCase().trim();
  if (!s) return null;
  const comptes = fd.comptes || (fd.soldesInitiaux && fd.soldesInitiaux.comptes) || [];
  // 1. Exact label match
  for (const c of comptes) {
    if (String(c.label || '').toLowerCase() === s) return c.id;
  }
  // 2. Substring match
  for (const c of comptes) {
    const lab = String(c.label || '').toLowerCase();
    if (lab && (lab.includes(s) || s.includes(lab))) return c.id;
  }
  return null;
}

// ── Actions ──
const results = [];
const touchedAnnees = new Set();

function addOne(tx) {
  const log = { action: 'add' };
  try {
    const amount = pickNum(tx, 'amount', 'montant', 'valeur', 'value');
    if (amount === null || amount <= 0) { log.status = 'error'; log.reason = 'montant invalide ou manquant'; return log; }
    const libelle = pickStr(tx, 'libelle', 'label', 'nom') || 'Sans libellé';
    const dt = tx.datetime || tx.date || todayDate;
    const dateOnly = (dt.length >= 10) ? dt.slice(0, 10) : todayDate;
    const annee = Number(tx.annee) || Number(dateOnly.slice(0, 4)) || currentAnnee;
    const mois = Number(tx.mois) || Number(dateOnly.slice(5, 7)) || currentMois;
    const categorieId = resolveCategorieId(tx.categorie || tx.categorieId, fd);
    const compteId = resolveCompteId(tx.compte || tx.compteId, fd);

    if (!fd.donneesAnnuelles) fd.donneesAnnuelles = {};
    if (!fd.donneesAnnuelles[annee]) { log.status = 'error'; log.reason = 'année ' + annee + ' absente du dataset'; return log; }
    if (!Array.isArray(fd.donneesAnnuelles[annee].transactionsReelles)) fd.donneesAnnuelles[annee].transactionsReelles = [];

    const newTx = {
      id: Date.now() + Math.floor(Math.random() * 1000),
      datetime: dt.length > 10 ? dt : null,
      date: dateOnly,
      mois,
      libelle,
      montant: amount,
      categorieId,
      compteId,
      source: tx.source || 'cfo'
    };
    fd.donneesAnnuelles[annee].transactionsReelles.push(newTx);
    touchedAnnees.add(annee);
    log.status = 'ok'; log.tx = newTx;
    return log;
  } catch (e) {
    log.status = 'error'; log.reason = e.message; return log;
  }
}

function removeOne(criteria) {
  const log = { action: 'remove' };
  const annee = Number(criteria.annee) || currentAnnee;
  if (!fd.donneesAnnuelles[annee] || !Array.isArray(fd.donneesAnnuelles[annee].transactionsReelles)) {
    log.status = 'skip'; log.reason = 'année ' + annee + ' sans transactions'; return log;
  }
  if (criteria.id === undefined) { log.status = 'error'; log.reason = 'id requis'; return log; }
  const before = fd.donneesAnnuelles[annee].transactionsReelles.length;
  fd.donneesAnnuelles[annee].transactionsReelles = fd.donneesAnnuelles[annee].transactionsReelles.filter(t => Number(t.id) !== Number(criteria.id));
  const removed = before - fd.donneesAnnuelles[annee].transactionsReelles.length;
  if (removed > 0) touchedAnnees.add(annee);
  log.status = removed > 0 ? 'ok' : 'skip';
  log.count = removed;
  log.id = criteria.id;
  return log;
}

function listTxs(criteria) {
  const log = { action: 'list' };
  const annee = Number(criteria.annee) || currentAnnee;
  const mois = criteria.mois ? Number(criteria.mois) : null;
  const txs = (fd.donneesAnnuelles[annee] && fd.donneesAnnuelles[annee].transactionsReelles) || [];
  const filtered = mois ? txs.filter(t => Number(t.mois) === mois) : txs;
  log.status = 'ok';
  log.annee = annee; log.mois = mois; log.count = filtered.length;
  log.transactions = filtered.slice(-20).map(t => ({
    id: t.id, date: t.datetime || t.date, libelle: t.libelle, montant: t.montant,
    categorie: t.categorieId, compte: t.compteId
  }));
  return log;
}

// ── Dispatch ──
const opsToProcess = Array.isArray(input.operations) && input.operations.length
  ? input.operations
  : (input.transaction ? [Object.assign({ action: input.action || 'add' }, input.transaction)] : [input]);

for (const op of opsToProcess) {
  const act = String(op.action || input.action || 'add').toLowerCase();
  if (act === 'add' || act === 'add_transaction_reelle') {
    results.push(addOne(op));
  } else if (act === 'remove' || act === 'remove_transaction_reelle' || act === 'delete') {
    results.push(removeOne(op));
  } else if (act === 'list' || act === 'list_transactions_reelles') {
    results.push(listTxs(op));
  } else {
    results.push({ status: 'error', reason: 'action inconnue: ' + act + ' (valides: add, remove, list)' });
  }
}

const successCount = results.filter(r => r.status === 'ok').length;
const errorCount = results.filter(r => r.status === 'error').length;
const isReadOnly = results.every(r => r.action === 'list');

// ── Commit direct (sauf si lecture seule) ──
let saved = false;
let saveError = null;
if (!isReadOnly && successCount > 0 && touchedAnnees.size > 0) {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://n8n.beau.ink/finance/save_data.php',
      body: fd,
      json: true,
      headers: { 'Content-Type': 'application/json' },
      timeout: 15000
    });
    saved = !!(resp && (resp.status === 'ok' || resp.success === true || resp === 'ok'));
    if (!saved && resp) saveError = 'Réponse VPS inattendue: ' + JSON.stringify(resp).slice(0, 200);
  } catch (e) {
    saveError = e.message;
  }
}

return JSON.stringify({
  tool: TOOL_NAME,
  operations_processed: results.length,
  success: successCount,
  errors: errorCount,
  touched_annees: Array.from(touchedAnnees),
  results,
  committed_to_vps: saved,
  save_error: saveError,
  hint: isReadOnly ? 'Lecture seule — aucun commit.' : (saved ? 'Transactions enregistrées DIRECTEMENT. Pas besoin de OUI.' : 'Aucun commit (erreurs ou aucune transaction ajoutée).')
}, null, 2);
